package com.example.sharehandler

import android.content.Intent
import android.graphics.Bitmap
import android.net.Uri
import android.os.Bundle
import android.util.Log
import androidx.appcompat.app.AppCompatActivity
import java.net.URL

class ShareHandlerActivity : AppCompatActivity() {
    private val TAG = "ShareHandlerActivity"
    
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        
        val action = intent.action
        val type = intent.type
        
        if (Intent.ACTION_SEND == action && type != null) {
            handleSendIntent()
        } else {
            Log.w(TAG, "Unhandled intent")
            finish()
        }
    }
    
    private fun handleSendIntent() {
        val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
        val sharedUri = intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM)
        
        if (sharedText != null) {
            processSharedText(sharedText)
        }
        
        if (sharedUri != null) {
            processSharedUri(sharedUri)
        }
        
        finish()
    }
    
    private fun processSharedText(text: String) {
        try {
            val url = URL(text)
            if (isValidUrl(url)) {
                Log.d(TAG, "Valid URL received: ${url.toString()}")
                // Process URL
            } else {
                Log.w(TAG, "Invalid URL format")
            }
        } catch (e: Exception) {
            Log.d(TAG, "Text is not a URL, treating as plain text")
            // Process plain text
        }
    }
    
    private fun processSharedUri(uri: Uri) {
        try {
            val scheme = uri.scheme
            if (scheme == "http" || scheme == "https") {
                Log.d(TAG, "Valid HTTP/HTTPS URI received: ${uri.toString()}")
                // Process URL URI
            } else if (scheme == "content") {
                Log.d(TAG, "Content URI received: ${uri.toString()}")
                // Process content URI
            } else {
                Log.w(TAG, "Unsupported URI scheme: $scheme")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Error processing URI", e)
        }
    }
    
    private fun isValidUrl(url: URL): Boolean {
        return url.protocol in listOf("http", "https") && 
               url.host.isNotEmpty() && 
               url.port != -1
    }
}

